/**
 * Represents the base structure for an entity.
 */
export interface BaseEntity {
    /**
     * The code representing the type of entity.
     * Possible values are:
     * - `'BUR'`: Burgerprofiel
     * - `'VER'`: Verenigingsloket
     * - `'EA'`: eLoket Ondernemers (Economische Actor)
     * - `'GID'`: Gemeenschappelijke Identificatiedienst
     * - `'LB'`: Lokale besturen
     * - `'OV'`: Openbare instellingen
     */
    code: 'BUR' | 'VER' | 'EA' | 'GID' | 'LB' | 'OV';
    /**
     * The name of the entity.
     */
    name: string;
    /**
     * An optional identifier for the entity.
     */
    identifier?: string;
}
/**
 * Represents an entity of type Gemeenschappelijke Identificatiedienst (GID).
 */
export interface GID extends BaseEntity {
    /**
     * The code for Gemeenschappelijke Identificatiedienst is always `'GID'`.
     */
    code: 'GID';
    /**
     * The identifier for GID is the ovoCode.
     */
    identifier?: string;
}
/**
 * Represents an entity of type Verenigingsloket (VER).
 */
export interface VER extends BaseEntity {
    /**
     * The code for Verenigingsloket is always `'VER'`.
     */
    code: 'VER';
    /**
     * Het verenigingsnummer van de vereniging.
     */
    identifier?: string;
}
/**
 * Represents an entity of type Lokale Besturen (LB).
 */
export interface LB extends BaseEntity {
    /**
     * The code for Lokale Besturen is always `'LB'`.
     */
    code: 'LB';
    /**
     * The identifier for LB is the 'ondernemingsnummer'.
     */
    identifier?: string;
}
/**
 * Represents an entity of type Openbare Instellingen (OV).
 */
export interface OV extends BaseEntity {
    /**
     * The code for Openbare Instellingen is always `'OV'`.
     */
    code: 'OV';
    /**
     * The identifier for OV is the instellingsnummer.
     */
    identifier?: string;
}
/**
 * Represents an entity of type eLoket Ondernemers (EA).
 */
export interface EA extends BaseEntity {
    /**
     * The code for eLoket Ondernemers is always `'EA'`.
     */
    code: 'EA';
    /**
     * The identifier for EA is the ondernemingsnummer.
     */
    identifier?: string;
}
/**
 * Represents an entity of type Burgerprofiel (BUR).
 */
export interface BUR extends BaseEntity {
    /**
     * The code for Burgerprofiel is always `'BUR'`.
     */
    code: 'BUR';
    /**
     * The name of the person associated with BUR.
     */
    name: string;
    /**
     * The first name of the person associated with BUR.
     */
    firstName: string;
}
/**
 * Represents a user with a first name and name.
 */
export interface User {
    /**
     * The first name of the user.
     */
    firstName: string;
    /**
     * The last name of the user.
     */
    name: string;
}
/**
 * Represents an entity, which can be either BUR, GID, VER, or EA.
 */
export type Entity = BUR | GID | VER | EA | LB | OV;
/**
 * Represents authorization information for a user.
 */
export interface Authorization {
    /**
     * The entity on behalf of which the user is acting, if applicable.
     */
    onBehalfOf?: Entity;
    /**
     * The mandate giver, which could be just the name of the mandate giver.
     */
    mandateGiver?: Entity;
    /**
     * A base64-encoded string representing a login hint.
     * In case of ACM, @see https://authenticatie.vlaanderen.be/docs/beveiligen-van-toepassingen/integratie-methoden/oauth/technische-info/gericht-aanmelden/
     */
    loginHint?: string;
}
/**
 * Represents the identity provider data.
 */
export interface IDPData {
    /**
     * The user who is being authorized.
     */
    user: User;
    /**
     * The active authorization for the current session.
     */
    activeIdentity?: Authorization;
    /**
     * An optional array of past or other possible authorizations that the user may have.
     */
    identities?: Authorization[];
}
